import{_ as r,a as e,d as o,k as l,i,J as n,o as s}from"./chunks/framework.CXVo2Jqr.js";const q=JSON.parse('{"title":"字根大全","description":"浏览和学习所有字根，支持搜索、筛选和排序","frontmatter":{"outline":"deep","title":"字根大全","description":"浏览和学习所有字根，支持搜索、筛选和排序"},"headers":[],"relativePath":"roots/index.md","filePath":"roots/index.md","lastUpdated":1773588811000}'),d={name:"roots/index.md"},h={class:"roots-gallery-page"};function c(g,a,p,u,m,f){const t=n("RootsGallery");return s(),e("div",null,[o("div",h,[l(t)]),a[0]||(a[0]=i('<h2 id="使用说明" tabindex="-1">使用说明 <a class="header-anchor" href="#使用说明" aria-label="Permalink to &quot;使用说明&quot;">​</a></h2><h3 id="🔍-快速搜索" tabindex="-1">🔍 快速搜索 <a class="header-anchor" href="#🔍-快速搜索" aria-label="Permalink to &quot;🔍 快速搜索&quot;">​</a></h3><p>在搜索框中输入字根字符、提示文字、编码或分类，即可快速找到目标字根。</p><h3 id="🏷️-分类筛选" tabindex="-1">🏷️ 分类筛选 <a class="header-anchor" href="#🏷️-分类筛选" aria-label="Permalink to &quot;🏷️ 分类筛选&quot;">​</a></h3><p>点击不同的分类标签，可以查看特定类别的字根：</p><ul><li><strong>全部</strong>：显示所有字根</li><li><strong>自然</strong>：与自然相关的字根（日、月、云等）</li><li><strong>人体</strong>：与人体相关的字根（人、手、口等）</li><li><strong>动物</strong>：与动物相关的字根（羊、犬等）</li><li><strong>植物</strong>：与植物相关的字根（木、禾等）</li><li><strong>数字</strong>：数字相关的字根（一、二、三等）</li><li><strong>笔画</strong>：基本笔画（横、竖、撇、捺等）</li><li><strong>结构</strong>：字形结构部件（偏旁部首等）</li><li><strong>其他</strong>：其他字根</li></ul><h3 id="🔤-编码筛选" tabindex="-1">🔤 编码筛选 <a class="header-anchor" href="#🔤-编码筛选" aria-label="Permalink to &quot;🔤 编码筛选&quot;">​</a></h3><p>通过下拉框选择特定编码（A-Z），查看该编码对应的所有字根。</p><h3 id="📊-排序方式" tabindex="-1">📊 排序方式 <a class="header-anchor" href="#📊-排序方式" aria-label="Permalink to &quot;📊 排序方式&quot;">​</a></h3><ul><li><strong>按编码</strong>：按字母顺序排列</li><li><strong>按字符</strong>：按 Unicode 编码排列</li></ul><h3 id="📄-分页浏览" tabindex="-1">📄 分页浏览 <a class="header-anchor" href="#📄-分页浏览" aria-label="Permalink to &quot;📄 分页浏览&quot;">​</a></h3><p>每页显示 50 个字根，可通过分页按钮查看更多。</p><h2 id="学习建议" tabindex="-1">学习建议 <a class="header-anchor" href="#学习建议" aria-label="Permalink to &quot;学习建议&quot;">​</a></h2><ol><li><strong>先学核心</strong>：优先掌握 20 个核心字根</li><li><strong>分类记忆</strong>：按分类逐个突破</li><li><strong>编码联想</strong>：记住每个编码对应的字根</li><li><strong>反复练习</strong>：使用练习页面巩固记忆</li></ol><h2 id="相关资源" tabindex="-1">相关资源 <a class="header-anchor" href="#相关资源" aria-label="Permalink to &quot;相关资源&quot;">​</a></h2><ul><li><a href="/practice/modern">顺序练习</a> - 系统化学习字根</li><li><a href="/practice/random">随机练习</a> - 检验学习成果</li><li><a href="/practice/top500">常用字根</a> - 高频字根专项</li><li><a href="/practice/error">错题本</a> - 强化薄弱环节</li></ul>',16))])}const x=r(d,[["render",c]]);export{q as __pageData,x as default};
